{"operationName":"GetSpotlightAd","variables":{"pageSkus":"6674708","partyId":"5117767577","placements":{"name":"PDP_SPONSORED_SPOTLIGHT","minSkus":1,"maxSkus":1,"pageType":""},"platform":"L","salesChannel":"LARGE_VIEW","storeId":"1436","userAgent":"Mozilla5.0 (Macintosh; Intel Mac OS X 10_15_7) AppleWebKit537.36 (KHTML like Gecko) Chrome147.0.0.0 Safari537.36","visitorId":"e616ea95-4828-4b2a-a078-2bf0bb59f33c","zipcode":"21117"},"extensions":{"clientLibrary":{"name":"@apollo/client","version":"4.1.6"}},"query":"query GetSpotlightAd($pageSkus: [String], $partyId: String, $placements: [BestMediaAdsPlacementInput], $platform: String!, $storeId: String, $userAgent: String!, $visitorId: String!, $xForwardedFor: String, $zipcode: String, $salesChannel: String!, $membershipTier: String, $cartTimestamp: String, $customerId: String) {
  bestMediaV3(
    input: {pageSkus: $pageSkus, partyId: $partyId, placements: $placements, platform: $platform, storeId: $storeId, visitorId: $visitorId, userAgent: $userAgent, xForwardedFor: $xForwardedFor, zipcode: $zipcode}
  ) {
    onLoadBeaconsForPage {
      source
      beacon
      __typename
    }
    placements {
      id
      name
      accepted {
        source
        sku
        onLoadBeaconForSku
        onClickBeaconForSku
        onViewBeaconForSku
        onWishlistBeaconForSku
        onBasketChangeBeaconForSku
        primaryCategoryId
        rank
        campaignId
        product {
          bsin
          name {
            short
            __typename
          }
          skuId
          primaryImage {
            piscesHref
            __typename
          }
          url {
            pdp
            skuSpecificUrl
            __typename
          }
          reviewInfo {
            averageRating
            reviewCount
            syndicatedReviewSummary {
              clientDisplayName
              overallRating
              totalReviewCount
              __typename
            }
            __typename
          }
          price(
            input: {salesChannel: $salesChannel, planPaidMemberType: $membershipTier, usePriceWithCart: true, cartTimestamp: $cartTimestamp, customerId: $customerId, visitorId: $visitorId}
          ) {
            customerPrice
            icrCode
            isMAP
            regularPrice
            preferredBadging
            saleEventMessageType
            strictMapIcr
            totalSavings
            __typename
          }
          __typename
          openBoxCondition
        }
        __typename
      }
      rejected {
        reason
        sku
        source
        __typename
      }
      onLoadBeaconsForPlacement {
        beacon
        source
        __typename
      }
      onViewBeaconsForPlacement {
        beacon
        source
        __typename
      }
      __typename
    }
    __typename
  }
}"}
